133	  <div class="left">
134	    <!-- BANNER -->
135	    <div class="banner" style="background:url('assets/images/banner.svg') center/cover no-repeat; padding:0; display:flex; align-items:flex-end; padding:20px 40px;">
136	      <div style="color:white; font-size:14px; opacity:0.9;">
137	        <div style="margin-top:40px; padding-bottom:20px;">선택한 고객 맞춤 추천이 준비되었습니다</div>
138	      </div>
139	    </div>
140	
141	    <!-- SEARCH RESULTS SECTION -->
142	    <div id="search-section" style="display:none;">
143	      <div class="sec-hdr">
144	        <h3 id="search-title">검색 결과</h3>
145	      </div>
146	      <div class="prod-grid" id="search-grid">
147	        <!-- Search results will be inserted here -->
148	      </div>
