190	function parseSearchQuery(query) {
191	    const filters = {};
192	    const words = query.split(/\s+/);
193	
194	    words.forEach(word => {
195	        if (searchMap[word]) {
196	            Object.assign(filters, searchMap[word]);
197	        } else {
198	            // 부분 매칭 (키워드 검색)
199	            if (!filters.keyword) filters.keyword = [];
200	            if (typeof filters.keyword === 'string') {
201	                filters.keyword = [filters.keyword];
202	            }
203	            filters.keyword.push(word);
204	        }
205	    });
206	
207	    return filters;
208	}
