210	function filterProducts(products, filters) {
211	    return products.filter(product => {
212	        // type 필터
213	        if (filters.type && product.type !== filters.type) {
214	            return false;
215	        }
216	
217	        // fuelType 필터
218	        if (filters.fuelType && product.fuelType !== filters.fuelType) {
219	            return false;
220	        }
221	
222	        // priority 필터
223	        if (filters.priority && product.priority !== filters.priority) {
224	            return false;
225	        }
226	
227	        // brand 필터
228	        if (filters.brand && product.brand !== filters.brand) {
229	            return false;
230	        }
231	
232	        // tag 필터
233	        if (filters.tag && !product.tag.includes(filters.tag)) {
234	            return false;
235	        }
236	
237	        // seats 필터
238	        if (filters.seats && product.seats < filters.seats) {
239	            return false;
240	        }
241	
242	        // 가격대 필터
243	        if (filters.priceMin && product.priceNum < filters.priceMin) {
244	            return false;
245	        }
246	        if (filters.priceMax && product.priceNum > filters.priceMax) {
247	            return false;
248	        }
249	
250	        // keyword 필터 (여러 키워드 중 하나라도 포함)
251	        if (filters.keyword) {
252	            const keywords = Array.isArray(filters.keyword) ? filters.keyword : [filters.keyword];
253	            const allKeywords = [...product.keywords, product.brand.toLowerCase(), product.name.toLowerCase()];
254	
255	            const hasMatch = keywords.some(kw => {
256	                return allKeywords.some(pk => pk.includes(kw));
257	            });
258	
259	            if (!hasMatch) {
260	                return false;
261	            }
262	        }
263	
264	        return true;
265	    });
266	}
