389	        for (let key in customer.preferences) {
390	            if (product.weights && product.weights[key]) {
391	                // 공통 항목이 높을수록 높은 점수
392	                const customerPref = customer.preferences[key];
393	                const productWeight = product.weights[key];
394	                score += (customerPref * productWeight) / 10;
395	                matchCount++;
396	            }
397	        }
398	
399	        score = matchCount > 0 ? score / matchCount : 0;
400	
401	        // 차종 일치 보너스
402	        if (customer.preferredCarType !== '전체' && product.type === customer.preferredCarType) {
403	            score += 5;
404	        }
405	
406	        return {
407	            ...product,
408	            recommendScore: Math.round(score * 10) / 10
409	        };
410	    });
411	
412	    // 높은 점수순으로 정렬
