/**
 * Wooricapital Auto Recommendation Prototype
 * 고객별 맞춤형 자동차 추천 + 자연어 검색
 */

// ============================================
// 전역 변수
// ============================================

let allCustomers = [];
let allProducts = [];
let allSearchQueries = [];
let currentCustomer = null;
let filteredProducts = [];

// 자연어 검색 매핑
const searchMap = {
  // 차종
  '세단': { type: 'sedan' },
  'sedan': { type: 'sedan' },
  'suv': { type: 'suv' },
  '에스유브이': { type: 'suv' },
  '엠피브': { type: 'mpv' },

  // 연비/환경
  '연비': { keyword: 'economy', fuelType: '하이브리드' },
  '하이브리드': { fuelType: '하이브리드' },
  '친환경': { fuelType: '하이브리드' },
  'hev': { fuelType: '하이브리드' },
  '경제적': { priority: 'economy' },

  // 성능
  '고성능': { priority: 'performance' },
  '성능': { priority: 'performance' },
  '스포츠': { priority: 'performance' },
  'awd': { keyword: 'AWD' },

  // 가격대
  '비싼': { priceMin: 60000000 },
  '저가': { priceMax: 40000000 },
  '저렴': { priceMax: 40000000 },
  '합리적': { priceMax: 50000000 },

  // 인원수
  '가족': { seats: 7 },
  '7인': { seats: 7 },
  '5인': { seats: 5 },

  // 브랜드/국가
  '수입': { tag: '수입' },
  '국산': { tag: '국산' },
  '제네시스': { brand: 'GENESIS' },
  '현대': { brand: 'HYUNDAI' },
  'hyundai': { brand: 'HYUNDAI' },
  '기아': { brand: 'KIA' },
  'kia': { brand: 'KIA' },
  'bmw': { brand: 'BMW' },
  '렉서스': { brand: 'LEXUS' },
  'lexus': { brand: 'LEXUS' },

  // 특수 기능
  'awd': { keyword: 'AWD' },
  '4륜': { keyword: 'AWD' },
};

// ============================================
// 초기화
// ============================================

document.addEventListener('DOMContentLoaded', async function () {
    console.log('페이지 로드 완료. 데이터 로딩...');

    try {
        // 데이터 로드
        await loadCustomers();
        await loadProducts();
        await loadSearchQueries();

        // 첫 번째 고객으로 자동 설정 (선택 모달 표시)
        showCustomerSelection();

        // 검색 이벤트 리스너
        const searchInput = document.getElementById('search-input');
        if (searchInput) {
            searchInput.addEventListener('input', handleSearch);
            searchInput.addEventListener('keypress', (e) => {
                if (e.key === 'Enter') {
                    handleSearch();
                }
            });
        }

    } catch (error) {
        console.error('데이터 로드 실패:', error);
    }
});

// ============================================
// 데이터 로드
// ============================================

async function loadCustomers() {
    try {
        const response = await fetch('data/customers.json');
        allCustomers = await response.json();
        console.log('고객 데이터 로드됨:', allCustomers.length);
        return allCustomers;
    } catch (error) {
        console.error('고객 데이터 로드 실패:', error);
        allCustomers = [
            {
                id: 'cust_001',
                name: '김준호',
                gender: '남',
                age: '30대',
                creditScore: 930,
                currentCar: '더뉴스포티지(NQ5)',
                expectedFeature: '주행성능',
                preferredCarType: '세단',
                preferences: { performance: 9, efficiency: 6, design: 7, safety: 8, comfort: 7 },
                isGuest: false,
                avatar: '👨'
            },
            {
                id: 'cust_002',
                name: '이수진',
                gender: '여',
                age: '20대',
                creditScore: 950,
                currentCar: 'C-CLASS(W206)',
                expectedFeature: '연비',
                preferredCarType: 'SUV',
                preferences: { performance: 6, efficiency: 10, design: 8, safety: 9, comfort: 8 },
                isGuest: false,
                avatar: '👩'
            },
            {
                id: 'cust_guest',
                name: '최승훈',
                gender: '남',
                age: '미정',
                creditScore: 0,
                currentCar: '없음',
                expectedFeature: '인기차종',
                preferredCarType: '전체',
                preferences: { performance: 5, efficiency: 5, design: 5, safety: 5, comfort: 5 },
                isGuest: true,
                avatar: '👤'
            }
        ];
    }
}

async function loadProducts() {
    try {
        const response = await fetch('data/products.json');
        allProducts = await response.json();
        console.log('상품 데이터 로드됨:', allProducts.length);
        return allProducts;
    } catch (error) {
        console.error('상품 데이터 로드 실패:', error);
        allProducts = [];
    }
}

async function loadSearchQueries() {
    try {
        const response = await fetch('data/search_queries.json');
        allSearchQueries = await response.json();
        console.log('검색쿼리 로드됨:', allSearchQueries.length);
    } catch (error) {
        console.error('검색쿼리 로드 실패:', error);
        allSearchQueries = [];
    }
}

// ============================================
// 검색 기능
// ============================================

async function handleSearch() {
    const query = document.getElementById('search-input').value.trim().toLowerCase();

    if (!query) {
        document.getElementById('search-section').style.display = 'none';
        document.getElementById('search-desc').style.display = 'none';
        document.getElementById('recommended-section').style.display = 'block';
        renderRecommendedProducts();
        return;
    }

    // search_queries.json 기반 매칭
    const words = query.split(/\s+/);
    let bestMatch = null;
    let bestScore = 0;

    allSearchQueries.forEach(sq => {
        const score = sq.keywords.filter(kw =>
            words.some(w => w.includes(kw) || kw.includes(w))
        ).length;
        if (score > bestScore) {
            bestScore = score;
            bestMatch = sq;
        }
    });

    if (bestMatch && bestScore > 0) {
        try {
            const response = await fetch(`data/search_results/${bestMatch.id}.json`);
            const resultData = await response.json();
            displaySearchResultCards(resultData);
            return;
        } catch (e) {
            console.error('검색결과 파일 로드 실패:', e);
        }
    }

    // Fallback: 필터 기반 검색
    const filters = parseSearchQuery(query);
    const results = filterProducts(allProducts, filters);
    displaySearchResults(results, query);
}

function parseSearchQuery(query) {
    const filters = {};
    const words = query.split(/\s+/);

    words.forEach(word => {
        if (searchMap[word]) {
            Object.assign(filters, searchMap[word]);
        } else {
            // 부분 매칭 (키워드 검색)
            if (!filters.keyword) filters.keyword = [];
            if (typeof filters.keyword === 'string') {
                filters.keyword = [filters.keyword];
            }
            filters.keyword.push(word);
        }
    });

    return filters;
}

function filterProducts(products, filters) {
    return products.filter(product => {
        // type 필터
        if (filters.type && product.type !== filters.type) {
            return false;
        }

        // fuelType 필터
        if (filters.fuelType && product.fuelType !== filters.fuelType) {
            return false;
        }

        // priority 필터
        if (filters.priority && product.priority !== filters.priority) {
            return false;
        }

        // brand 필터
        if (filters.brand && product.brand !== filters.brand) {
            return false;
        }

        // tag 필터
        if (filters.tag && !product.tag.includes(filters.tag)) {
            return false;
        }

        // seats 필터
        if (filters.seats && product.seats < filters.seats) {
            return false;
        }

        // 가격대 필터
        if (filters.priceMin && product.priceNum < filters.priceMin) {
            return false;
        }
        if (filters.priceMax && product.priceNum > filters.priceMax) {
            return false;
        }

        // keyword 필터 (여러 키워드 중 하나라도 포함)
        if (filters.keyword) {
            const keywords = Array.isArray(filters.keyword) ? filters.keyword : [filters.keyword];
            const allKeywords = [...product.keywords, product.brand.toLowerCase(), product.name.toLowerCase()];

            const hasMatch = keywords.some(kw => {
                return allKeywords.some(pk => pk.includes(kw));
            });

            if (!hasMatch) {
                return false;
            }
        }

        return true;
    });
}

function displaySearchResultCards(resultData) {
    const searchGrid = document.getElementById('search-grid');
    const searchDesc = document.getElementById('search-desc');

    document.getElementById('search-section').style.display = 'block';
    document.getElementById('recommended-section').style.display = 'none';
    document.getElementById('search-title').textContent = resultData.title;

    if (resultData.description) {
        searchDesc.textContent = resultData.description;
        searchDesc.style.display = 'block';
    } else {
        searchDesc.style.display = 'none';
    }

    searchGrid.innerHTML = resultData.cars.map(car => `
        <div class="prod-card">
            <div class="pc-img">
                <img src="assets/images/${car.img}.png" alt="${car.brand}" onerror="this.style.display='none'">
                <span class="pc-tag ${car.tagC}">${car.tag}</span>
                ${car.highlight ? `<div class="pc-highlight">${car.highlight}</div>` : ''}
                <div class="pc-btns">
                    <button class="pc-btn" onclick="viewDetails('${car.img}')">상세</button>
                    <button class="pc-btn" onclick="selectProduct('${car.img}')">선택</button>
                </div>
            </div>
            <div class="pc-info">
                <div class="pc-brand">${car.brand}</div>
                <div class="pc-name">${car.name}</div>
